// Flyweight — stores intrinsic (shared) state
class TreeType {
  constructor(name, color, texture) {
    this.name    = name;
    this.color   = color;
    this.texture = texture;
  }

  draw(x, y) {
    console.log(
      `Drawing ${this.name} [${this.color}, ${this.texture}] at (${x}, ${y})`
    );
  }
}

// Flyweight Factory — manages the shared pool
class TreeTypeFactory {
  static #types = new Map();

  static getTreeType(name, color, texture) {
    const key = `${name}_${color}_${texture}`;
    if (!TreeTypeFactory.#types.has(key)) {
      TreeTypeFactory.#types.set(key, new TreeType(name, color, texture));
      console.log(`Factory: created new type '${name}'`);
    }
    return TreeTypeFactory.#types.get(key);
  }

  static getCount() { return TreeTypeFactory.#types.size; }
}

// Context — stores extrinsic (unique) state, references the flyweight
class Tree {
  constructor(x, y, type) {
    this.x    = x;
    this.y    = y;
    this.type = type;
  }

  draw() { this.type.draw(this.x, this.y); }
}

// Client — creates many trees reusing shared flyweights
class Forest {
  #trees = [];

  plantTree(x, y, name, color, texture) {
    const type = TreeTypeFactory.getTreeType(name, color, texture);
    this.#trees.push(new Tree(x, y, type));
  }

  draw() { this.#trees.forEach(t => t.draw()); }
}

// Usage
const forest = new Forest();
forest.plantTree(1, 2, 'Oak',  'green',      'rough');  // Factory: created new type 'Oak'
forest.plantTree(5, 8, 'Oak',  'green',      'rough');  // reused
forest.plantTree(3, 4, 'Pine', 'dark-green', 'smooth'); // Factory: created new type 'Pine'
forest.plantTree(7, 1, 'Pine', 'dark-green', 'smooth'); // reused

console.log(`Trees: 4 | Unique types: ${TreeTypeFactory.getCount()}`);
// Trees: 4 | Unique types: 2

forest.draw();
// Drawing Oak  [green, rough]       at (1, 2)
// Drawing Oak  [green, rough]       at (5, 8)
// Drawing Pine [dark-green, smooth] at (3, 4)
// Drawing Pine [dark-green, smooth] at (7, 1)

