from __future__ import annotations


class TreeType:
    def __init__(self, name: str, color: str, texture: str) -> None:
        self.name    = name
        self.color   = color
        self.texture = texture

    def draw(self, x: int, y: int) -> None:
        print(f'Drawing {self.name} [{self.color}, {self.texture}] at ({x}, {y})')


class TreeTypeFactory:
    _types: dict[str, TreeType] = {}

    @classmethod
    def get_tree_type(cls, name: str, color: str, texture: str) -> TreeType:
        key = f'{name}_{color}_{texture}'
        if key not in cls._types:
            cls._types[key] = TreeType(name, color, texture)
            print(f"Factory: created new type '{name}'")
        return cls._types[key]

    @classmethod
    def get_count(cls) -> int:
        return len(cls._types)


class Tree:
    def __init__(self, x: int, y: int, tree_type: TreeType) -> None:
        self.x    = x
        self.y    = y
        self.type = tree_type

    def draw(self) -> None:
        self.type.draw(self.x, self.y)


class Forest:
    def __init__(self) -> None:
        self._trees: list[Tree] = []

    def plant_tree(self, x: int, y: int, name: str, color: str, texture: str) -> None:
        tree_type = TreeTypeFactory.get_tree_type(name, color, texture)
        self._trees.append(Tree(x, y, tree_type))

    def draw(self) -> None:
        for tree in self._trees:
            tree.draw()


# Usage
forest = Forest()
forest.plant_tree(1, 2, 'Oak',  'green',      'rough')   # Factory: created new type 'Oak'
forest.plant_tree(5, 8, 'Oak',  'green',      'rough')   # reused
forest.plant_tree(3, 4, 'Pine', 'dark-green', 'smooth')  # Factory: created new type 'Pine'
forest.plant_tree(7, 1, 'Pine', 'dark-green', 'smooth')  # reused

print(f'Trees: 4 | Unique types: {TreeTypeFactory.get_count()}')
# Trees: 4 | Unique types: 2

forest.draw()
# Drawing Oak  [green, rough]       at (1, 2)
# Drawing Oak  [green, rough]       at (5, 8)
# Drawing Pine [dark-green, smooth] at (3, 4)
# Drawing Pine [dark-green, smooth] at (7, 1)
